// --- Nesting ---

func tsComputeNesting(node *sitter.Node, depth int) int {
	maxDepth := depth
	for i := 0; i < int(node.ChildCount()); i++ {
		child := node.Child(i)
		switch child.Type() {
		case "if_statement", "for_statement", "for_in_statement", "while_statement",
			"do_statement", "switch_statement", "try_statement":
			d := depth + 1
			if d > maxDepth {
				maxDepth = d
			}
			inner := tsComputeNesting(child, d)
			if inner > maxDepth {
				maxDepth = inner
			}
		default:
			inner := tsComputeNesting(child, depth)
			if inner > maxDepth {
				maxDepth = inner
			}
		}
	}
	return maxDepth
}

func tsComputeLoopNesting(node *sitter.Node, depth int) int {
	maxDepth := 0
	for i := 0; i < int(node.ChildCount()); i++ {
		child := node.Child(i)
		switch child.Type() {
		case "for_statement", "for_in_statement", "while_statement", "do_statement":
			d := depth + 1
			if d > maxDepth {
				maxDepth = d
			}
			inner := tsComputeLoopNesting(child, d)
			if inner > maxDepth {
				maxDepth = inner
			}
		default:
			inner := tsComputeLoopNesting(child, depth)
			if inner > maxDepth {
				maxDepth = inner
			}
		}
	}
	return maxDepth
}

// --- Complexity ---

func tsComputeCyclomatic(body *sitter.Node) int {
	complexity := 1
	tsWalkAll(body, func(n *sitter.Node) {
		switch n.Type() {
		case "if_statement":
			complexity++
		case "for_statement", "for_in_statement", "while_statement", "do_statement":
			complexity++
		case "switch_case":
			// Only non-default cases
			if tsChildByType(n, "default") == nil {
				complexity++
			}
		case "catch_clause":
			complexity++
		case "ternary_expression":
			complexity++
		case "binary_expression":
			op := ""
			for j := 0; j < int(n.ChildCount()); j++ {
				c := n.Child(j)
				if c.Type() == "&&" || c.Type() == "||" {
					op = c.Type()
				}
			}
			if op == "&&" || op == "||" {
				complexity++
			}
		}
	})
	return complexity
}

func tsComputeCognitive(node *sitter.Node, nesting int) int {
	total := 0
	for i := 0; i < int(node.ChildCount()); i++ {
		child := node.Child(i)
		switch child.Type() {
		case "if_statement":
			total += 1 + nesting
			// Check for else
			for j := 0; j < int(child.ChildCount()); j++ {
				c := child.Child(j)
				if c.Type() == "else_clause" {
					total += 1
					total += tsComputeCognitive(c, nesting+1)
				} else if c.Type() == "statement_block" || c.Type() == "if_statement" {
					total += tsComputeCognitive(c, nesting+1)
				}
			}

		case "for_statement", "for_in_statement", "while_statement", "do_statement":
			total += 1 + nesting
			total += tsComputeCognitive(child, nesting+1)

		case "switch_statement":
			total += 1 + nesting
			total += tsComputeCognitive(child, nesting+1)

		case "catch_clause":
			total += 1 + nesting
			total += tsComputeCognitive(child, nesting+1)

		case "binary_expression":
			for j := 0; j < int(child.ChildCount()); j++ {
				c := child.Child(j)
				if c.Type() == "&&" || c.Type() == "||" {
					total += 1
				}
			}
			total += tsComputeCognitive(child, nesting)

		default:
			total += tsComputeCognitive(child, nesting)
		}
	}
	return total
}

